        call.cancel();
      }
      responsemetadata.set(TRUNCATED_CONTENT,"true");
      responsemetadata.set(TRUNCATED_CONTENT_REASON,truncated.getReason().toString().toLowerCase(Locale.ROOT));
      LOG.debug("HTTP content truncated to {} bytes (reason: {})",this.content.length,truncated.getReason());
    }
    this.code=response.code();
    this.headers=responsemetadata;
  }
 }

