      System.out.format("=> deletion\n");
      alignmentsInProgress.push(new Alignment(searchTerm.charAt(ali.r - 1) + ali.searchTermString,"-" + ali.searchTextString,ali.prob,ali.matchStart,ali.matchEnd,ali.r - 1,ali.c));
    }
    if (ali.r >= 2 && ali.c >= 2 && matrix[ali.r][ali.c] == matrix[ali.r - 2][ali.c - 2] + costTranspos && searchTerm.charAt(ali.r - 2) == searchText.charAt(ali.c - 1) && searchTerm.charAt(ali.r - 1) == searchText.charAt(ali.c - 2)) {
      System.out.format("=> transposition\n");
